// Generic math constraint — enforces numeric type safety at compile time
using System.Numerics;

static T Sum<T>(IEnumerable<T> values) where T : INumber<T>
{
    T total = T.Zero;
    foreach (var v in values)
        total += v;
    return total;
}

Console.WriteLine(Sum(new[] { 1, 2, 3 }));       // int: 6
Console.WriteLine(Sum(new[] { 1.1, 2.2, 3.3 })); // double: 6.6
