using System.Diagnostics.Tracing;

public sealed class GcPauseListener : EventListener
{
    private long _suspendStart;

    protected override void OnEventSourceCreated(EventSource src)
    {
        if (src.Name == "Microsoft-Windows-DotNETRuntime")
            EnableEvents(src, EventLevel.Informational, (EventKeywords)0x1); // GC keyword
    }

    protected override void OnEventWritten(EventWrittenEventArgs e)
    {
        if (e.EventName == "GCSuspendEEBegin")
            _suspendStart = Stopwatch.GetTimestamp();
        else if (e.EventName == "GCSuspendEEEnd")
        {
            var pauseMs = Stopwatch.GetElapsedTime(_suspendStart).TotalMilliseconds;
            Console.WriteLine($"GC pause: {pauseMs:F2} ms | Gen {e.Payload![0]}");
        }
    }
}
